from dataclasses import dataclass
from typing import List, Optional


BASE_ID = 37370000


@dataclass
class LocationData:
    name: str
    ap_id: int
    region: str = "Fortress"
    goal_only: bool = False  # if True, only relevant for a specific goal
    material_type: str = ""
    df_item: str = ""
    threshold: int = 0


